/*
 * acosh() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly acosh  (test_acosh_opt.elf)
 *   2. Linked with toolchain's default acosh       (test_acosh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += acosh(vx);
#else
    double r = acosh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for acosh()     */
/*                                                                     */
/* Domain: x >= 1.0; x < 1.0 returns NaN (domain error)              */
/* acosh(x) = ln(x + sqrt(x^2 - 1))                                  */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);                                        /* +0.0: domain error, returns NaN */
    emit(-0.0);                                       /* -0.0: domain error, returns NaN */
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf: acosh(+Inf) = +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf: domain error, returns NaN */

    /* --- Section 2: Domain-error inputs x < 1 (8) --- */
    emit_u(0x3feffffffffffffeULL);  /* 1.0 - 2 ULP: just below domain boundary */
    emit_u(0x3fefffffffffffffULL);  /* 1.0 - 1 ULP: one below domain boundary */
    emit(0.9);                                        /* 0.9: domain error */
    emit(0.5);                                        /* 0.5: domain error */
    emit(0.0 + DBL_MIN);                              /* DBL_MIN ~ 2.2e-308: domain error */
    emit(-0.5);                                       /* -0.5: domain error */
    emit(-1.0);                                       /* -1.0: domain error */
    emit(-1.0e10);                                    /* large negative: domain error */

    /* --- Section 3: Exact domain boundary - near 1.0 (12) --- */
    emit_u(0x3ff0000000000000ULL);  /* 1.0 exactly: acosh(1) = 0 */
    emit_u(0x3ff0000000000001ULL);  /* 1.0 + 1 ULP */
    emit_u(0x3ff0000000000002ULL);  /* 1.0 + 2 ULP */
    emit_u(0x3ff0000000000004ULL);  /* 1.0 + 4 ULP */
    emit_u(0x3ff0000000000008ULL);  /* 1.0 + 8 ULP */
    emit_u(0x3ff0000000000010ULL);  /* 1.0 + 16 ULP */
    emit_u(0x3ff0000000000020ULL);  /* 1.0 + 32 ULP */
    emit_u(0x3ff0000000000040ULL);  /* 1.0 + 64 ULP */
    emit_u(0x3ff0000000000100ULL);  /* 1.0 + 256 ULP */
    emit_u(0x3ff0000000001000ULL);  /* 1.0 + 4096 ULP */
    emit_u(0x3ff0000000010000ULL);  /* 1.0 + 65536 ULP */
    emit_u(0x3ff0000000100000ULL);  /* 1.0 + 1M ULP: still very close to 1 */

    /* --- Section 4: Small excess above 1.0 (8) --- */
    emit(1.0 + 1.0e-15);                              /* 1 + 1e-15: tiny excess */
    emit(1.0 + 1.0e-12);                              /* 1 + 1e-12 */
    emit(1.0 + 1.0e-9);                               /* 1 + 1e-9 */
    emit(1.0 + 1.0e-6);                               /* 1 + 1e-6 */
    emit(1.0 + 1.0e-4);                               /* 1 + 1e-4 */
    emit(1.0 + 1.0e-3);                               /* 1 + 0.001 */
    emit(1.0 + 1.0e-2);                               /* 1 + 0.01 */
    emit(1.0 + 1.0e-1);                               /* 1.1 */

    /* --- Section 5: Known mathematical values (10) --- */
    /* acosh(cosh(k)) = k for integer k */
    emit(1.5430806348152437);   /* cosh(1): acosh -> 1.0 */
    emit(3.7621956910213472);   /* cosh(2): acosh -> 2.0 */
    emit(10.067661995777766);   /* cosh(3): acosh -> 3.0 */
    emit(27.308232836016487);   /* cosh(4): acosh -> 4.0 */
    emit(2.0);                  /* acosh(2) = ln(2 + sqrt(3)) ~ 1.3170 */
    emit(2.718281828459045);    /* acosh(e) ~ 1.6574 */
    emit(1.4142135623730951);   /* acosh(sqrt(2)) ~ 0.8814 */
    emit(11.591953275521521);   /* cosh(pi): acosh -> pi */
    emit(10.0);                 /* acosh(10) ~ 2.9932 */
    emit(100.0);                /* acosh(100) ~ 5.2983 */

    /* --- Section 6: Moderate range [1.1, 20] (10) --- */
    emit(1.1);
    emit(1.2);
    emit(1.5);
    emit(1.7320508075688772);   /* sqrt(3) */
    emit(3.0);
    emit(4.0);
    emit(5.0);
    emit(7.0);
    emit(13.0);
    emit(20.0);

    /* --- Section 7: Large arguments (10) --- */
    emit(1.0e2);
    emit(1.0e4);
    emit(1.0e8);
    emit(1.0e10);
    emit(1.0e15);               /* range where acosh(x) ~ ln(2x) */
    emit(1.0e20);
    emit(1.0e50);
    emit(1.0e100);
    emit(1.0e200);
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: acosh(DBL_MAX) ~ ln(2*DBL_MAX) */

    /* --- Section 8: Power-of-2 inputs (8) --- */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x4010000000000000ULL);  /* 4.0 */
    emit_u(0x4020000000000000ULL);  /* 8.0 */
    emit_u(0x4030000000000000ULL);  /* 16.0 */
    emit_u(0x4040000000000000ULL);  /* 32.0 */
    emit_u(0x4050000000000000ULL);  /* 64.0 */
    emit_u(0x4060000000000000ULL);  /* 128.0 */
    emit_u(0x4070000000000000ULL);  /* 256.0 */

    /* --- Section 9: ULP neighbors of x = cosh(k) for k = 1..5 (15) --- */
    /* cosh(1) = 1.5430806348152437 = 0x3ff8b07551d9f550 */
    emit_u(0x3ff8b07551d9f54fULL);  /* cosh(1) - 1 ULP */
    emit_u(0x3ff8b07551d9f550ULL);  /* cosh(1) exact */
    emit_u(0x3ff8b07551d9f551ULL);  /* cosh(1) + 1 ULP */
    /* cosh(2) = 3.7621956910213472 = 0x400e18fa0df2d9bcULL */
    emit_u(0x400e18fa0df2d9bbULL);  /* cosh(2) - 1 ULP */
    emit_u(0x400e18fa0df2d9bcULL);  /* cosh(2) exact */
    emit_u(0x400e18fa0df2d9bdULL);  /* cosh(2) + 1 ULP */
    /* cosh(3) = 10.067661995777766 = 0x40241900fc7f4285ULL */
    emit_u(0x40241900fc7f4284ULL);  /* cosh(3) - 1 ULP */
    emit_u(0x40241900fc7f4285ULL);  /* cosh(3) exact */
    emit_u(0x40241900fc7f4286ULL);  /* cosh(3) + 1 ULP */
    /* cosh(4) = 27.308232836016487 = 0x403b4a2ef4e7bb14ULL */
    emit_u(0x403b4a2ef4e7bb13ULL);  /* cosh(4) - 1 ULP */
    emit_u(0x403b4a2ef4e7bb14ULL);  /* cosh(4) exact */
    emit_u(0x403b4a2ef4e7bb15ULL);  /* cosh(4) + 1 ULP */
    /* cosh(5) = 74.20994852478785 = 0x40528d0417428b10ULL */
    emit_u(0x40528d0417428b0fULL);  /* cosh(5) - 1 ULP */
    emit_u(0x40528d0417428b10ULL);  /* cosh(5) exact */
    emit_u(0x40528d0417428b11ULL);  /* cosh(5) + 1 ULP */

    /* --- Section 10: Hard rounding / ULP stress (12) --- */
    /* ULP neighbors of 2.0 input */
    emit_u(0x3ffffffffffffffeULL);  /* 2.0 - 2 ULP */
    emit_u(0x3fffffffffffffffULL);  /* 2.0 - 1 ULP */
    emit_u(0x4000000000000001ULL);  /* 2.0 + 1 ULP */
    /* ULP neighbors of 10.0 input */
    emit_u(0x4023fffffffffffcULL);  /* 10.0 - 4 ULP */
    emit_u(0x4024000000000000ULL);  /* 10.0 exact */
    emit_u(0x4024000000000004ULL);  /* 10.0 + 4 ULP */
    /* Near ln(2) overflow path: argument where acosh(x) ~ ln(2x) takes over */
    emit(1.0e7);
    emit(1.0e8 + 1.0);
    /* Inputs that produce acosh near integer multiples of ln2 */
    emit(1.3862943611198906);   /* cosh(ln2) ~ 1.25: acosh(1.25) ~ ln(1.25+...) */
    emit(1.25);
    emit(1.75);
    emit(9.0);
}
#endif /* !EN_PERF */

